    final signature = _getSignature(stringToSign, signingKey);
    
    final headers = {
      'Authorization': 'AWS4-HMAC-SHA256 Credential=$awsAccessKey/$dateString/$region/s3/aws4_request, SignedHeaders=host;x-amz-date, Signature=$signature',
      'x-amz-date': dateString,
      'Content-Type': contentType,
